import scala.xml.{XML, Node}

class ConfigService {

  def parseConfig(xmlString: String): Map[String, String] = {
    val xml: Node = XML.loadString(xmlString)
    extractSettings(xml)
  }

  private def extractSettings(node: Node): Map[String, String] = {
    node.child.flatMap { child =>
      child.label match {
        case "setting" => Some((child \@ "name", child.text))
        case _ => None
      }
    }.toMap
  }
}

object ConfigService extends App {
  val configService = new ConfigService()
  val xmlString =
    """
      |<config>
      |  <setting name="databaseUrl">jdbc:mysql://localhost:3306/mydb</setting>
      |  <setting name="maxConnections">10</setting>
      |</config>
    """.stripMargin

  val settings = configService.parseConfig(xmlString)
  println(settings)
}